// Sadə generic interfeys
interface Container<T> {
  value: T;
  display(): string;
}

let stringContainer: Container<string> = {
  value: 'Hello',
  display() {
    return `Value: ${this.value}`;
  }
};

let numberContainer: Container<number> = {
  value: 42,
  display() {
    return `Value: ${this.value}`;
  }
};

console.log(stringContainer.display()); // Value: Hello
console.log(numberContainer.display()); // Value: 42
// let errorContainer: Container<number> = { value: 'test', display: () => 'test' }; // Xəta: 'test' number tipinə uyğun deyil

// Adi interfeys ilə generic interfeysin müqayisəsi
interface NumberContainer {
  value: number;
  display(): string;
}

interface GenericContainer<T> {
  value: T;
  display(): string;
}

let numberContainer: NumberContainer = {
  value: 10,
  display() {
    return `Value: ${this.value}`;
  }
};

let genericContainer: GenericContainer<string> = {
  value: 'Hello',
  display() {
    return `Value: ${this.value}`;
  }
};

console.log(numberContainer.display()); // Value: 10
console.log(genericContainer.display()); // Value: Hello

// Çoxsaylı tip parametrləri
interface Pair<K, V> {
  key: K;
  value: V;
}

let numberStringPair: Pair<number, string> = { key: 1, value: 'one' };
let stringBooleanPair: Pair<string, boolean> = { key: 'active', value: true };

console.log(numberStringPair); // { key: 1, value: 'one' }
console.log(stringBooleanPair); // { key: 'active', value: true }
// let errorPair: Pair<number, string> = { key: 'test', value: 'test' }; // Xəta: 'test' number tipinə uyğun deyil

// Generic interfeys ilə tip aliasının müqayisəsi
interface GenericInterface<T> {
  value: T;
}

type GenericType<T> = {
  value: T;
};

let interfaceExample: GenericInterface<string> = { value: 'Hello' };
let typeExample: GenericType<number> = { value: 42 };

console.log(interfaceExample); // { value: 'Hello' }
console.log(typeExample); // { value: 42 }

// Generic interfeys ilə sinif
interface Container<T> {
  value: T;
  display(): string;
}

class StringContainer implements Container<string> {
  value: string;
  constructor(value: string) {
    this.value = value;
  }
  display(): string {
    return `Value: ${this.value}`;
  }
}

let container = new StringContainer('Test');
console.log(container.display()); // Value: Test
// let errorContainer = new StringContainer(42); // Xəta: 42 string tipinə uyğun deyil

// Generic interfeys ilə funksiya
interface Response<T> {
  data: T;
  status: number;
}

function processResponse<T>(response: Response<T>): T {
  return response.data;
}

let userResponse: Response<{ name: string }> = {
  data: { name: 'Alice' },
  status: 200
};

console.log(processResponse(userResponse)); // { name: 'Alice' }

// Generic məhdudiyyət nümunəsi
interface Lengthy<T extends { length: number }> {
  value: T;
  getLength(): number;
}

class LengthContainer implements Lengthy<string> {
  value: string;
  constructor(value: string) {
    this.value = value;
  }
  getLength(): number {
    return this.value.length;
  }
}

let container = new LengthContainer('Hello');
console.log(container.getLength()); // 5
// let errorContainer = new LengthContainer(42); // Xəta: 42 length xüsusiyyətinə malik deyil

// Təhlükəsizlik nümunəsi
interface Keyed<T, K extends keyof T> {
  getProperty(key: K): T[K];
}

class PropertyContainer implements Keyed<{ name: string; age: number }, 'name' | 'age'> {
  data = { name: 'Alice', age: 30 };
  getProperty(key: 'name' | 'age') {
    return this.data[key];
  }
}

let container = new PropertyContainer();
console.log(container.getProperty('name')); // Alice
console.log(container.getProperty('age')); // 30
// console.log(container.getProperty('address')); // Xəta: 'address' mövcud deyil

// Səhvə yol açan nümunə
interface UnsafeContainer {
  value: any;
}

let unsafeContainer: UnsafeContainer = { value: 'Hello' };
console.log(unsafeContainer.value); // Hello, lakin tip təhlükəsizliyi yoxdur
unsafeContainer.value = 42; // Keçərlidir, lakin təhlükəsiz deyil

// Düzgün yol
interface SafeContainer<T> {
  value: T;
}

let safeContainer: SafeContainer<string> = { value: 'Hello' };
console.log(safeContainer.value); // Hello
// safeContainer.value = 42; // Xəta: 42 string tipinə uyğun deyil

// Real layihə ssenarisi
interface ApiResponse<T> {
  data: T;
  status: number;
}

let userResponse: ApiResponse<{ name: string; age: number }> = {
  data: { name: 'Alice', age: 30 },
  status: 200
};

let productResponse: ApiResponse<{ id: number; name: string }> = {
  data: { id: 1, name: 'Laptop' },
  status: 200
};

console.log(userResponse.data); // { name: 'Alice', age: 30 }
console.log(productResponse.data); // { id: 1, name: 'Laptop' }

